// If import paths are wrong after first build, check gui/src/main/native/generated/stoch-fit-proto/.
import { InitRequest } from './generated/stoch-fit-proto/init-request';
import { ReflSettings as FBReflSettings } from './generated/stoch-fit-proto/refl-settings';
import { StochRunState as FBStochRunState } from './generated/stoch-fit-proto/stoch-run-state';
import { GetDataResult } from './generated/stoch-fit-proto/get-data-result';
